+import androidx.test.ext.junit.runners.AndroidJUnit4;
+import com.google.common.collect.ImmutableList;
+import com.google.common.util.concurrent.MoreExecutors;
+import java.lang.reflect.Constructor;
+import java.lang.reflect.Field;
+import java.lang.reflect.InvocationTargetException;
+import java.lang.reflect.Method;
+import java.util.List;
+import org.objenesis.ObjenesisStd;
+import org.junit.Test;
+import org.junit.runner.RunWith;
+
+/** Tests the color-change trigger path in {@link DefaultVideoFrameProcessor}. */
+@RunWith(AndroidJUnit4.class)
+public final class DefaultVideoFrameProcessorColorChangeTest {
+
+  @Test
+  public void configureEffects_withDifferentInputColorInfos_registersSecondStream()
+      throws Exception {
+    VideoFrameProcessingTaskExecutor taskExecutor = newTaskExecutor();
+    try {
+      GlObjectsProvider glObjectsProvider = mock(GlObjectsProvider.class);
+      TextureManager textureManager = mock(TextureManager.class);
+      ExternalShaderProgram samplingShaderProgram = mock(ExternalShaderProgram.class);
+      GlShaderProgram downstreamShaderProgram = mock(GlShaderProgram.class);
+      VideoFrameProcessor.Listener listener = mock(VideoFrameProcessor.Listener.class);
+      ColorInfo firstColorInfo = ColorInfo.SDR_BT709_LIMITED;
+      ColorInfo secondColorInfo = ColorInfo.SRGB_BT709_FULL;
+      FrameInfo firstFrameInfo =
+          new FrameInfo.Builder(firstColorInfo, /* width= */ 100, /* height= */ 100).build();
+      FrameInfo secondFrameInfo =
+          new FrameInfo.Builder(secondColorInfo, /* width= */ 100, /* height= */ 100).build();
+      Object input = newInput(textureManager);
+      invokeInputSetSamplingGlShaderProgram(input, samplingShaderProgram);
+      setInputColorInfoIfPresent(input, firstColorInfo);
+      InputSwitcher inputSwitcher =
+          newInputSwitcher(
+              taskExecutor, glObjectsProvider, downstreamShaderProgram, textureManager, input);
+      DefaultVideoFrameProcessor processor =
+          newDefaultVideoFrameProcessor(
+              inputSwitcher, taskExecutor, glObjectsProvider, listener, ColorInfo.SDR_BT709_LIMITED);
+
+      invokeConfigureEffects(
+          processor,
+          newInputStreamInfo(
+              VideoFrameProcessor.INPUT_TYPE_BITMAP, ImmutableList.of(), firstFrameInfo));
+      setInputColorInfoIfPresent(input, secondColorInfo);
+      invokeConfigureEffects(
+          processor,
+          newInputStreamInfo(
+              VideoFrameProcessor.INPUT_TYPE_BITMAP, ImmutableList.of(), secondFrameInfo));
+
+      verify(textureManager).setInputFrameInfo(firstFrameInfo);
+      verify(textureManager).setInputFrameInfo(secondFrameInfo);
+      verify(listener)
+          .onInputStreamRegistered(
+              VideoFrameProcessor.INPUT_TYPE_BITMAP, ImmutableList.of(), firstFrameInfo);
+      verify(listener)
+          .onInputStreamRegistered(
+              VideoFrameProcessor.INPUT_TYPE_BITMAP, ImmutableList.of(), secondFrameInfo);
+    } finally {
+      release(taskExecutor);
+    }
+  }
+
+  @Test
+  public void inputSetSamplingGlShaderProgram_releasesPreviousProgram() throws Exception {
+    TextureManager textureManager = mock(TextureManager.class);
+    ExternalShaderProgram firstProgram = mock(ExternalShaderProgram.class);
+    ExternalShaderProgram secondProgram = mock(ExternalShaderProgram.class);
+    Object input = newInput(textureManager);
+
+    invokeInputSetSamplingGlShaderProgram(input, firstProgram);
+    invokeInputSetSamplingGlShaderProgram(input, secondProgram);
+
+    verify(textureManager).setSamplingGlShaderProgram(firstProgram);
+    verify(textureManager).setSamplingGlShaderProgram(secondProgram);
+    verify(firstProgram).setInputListener(textureManager);
+    verify(secondProgram).setInputListener(textureManager);
+    verify(firstProgram).release();
+  }
+
+  private static DefaultVideoFrameProcessor newDefaultVideoFrameProcessor(
+      InputSwitcher inputSwitcher,
+      VideoFrameProcessingTaskExecutor taskExecutor,
+      GlObjectsProvider glObjectsProvider,
+      VideoFrameProcessor.Listener listener,
+      ColorInfo outputColorInfo)
+      throws Exception {
+    FinalShaderProgramWrapper finalShaderProgramWrapper =
+        new FinalShaderProgramWrapper(
+            getApplicationContext(),
+            /* eglDisplay= */ null,
+            /* eglContext= */ null,
+            DebugViewProvider.NONE,
+            outputColorInfo,
+            /* enableColorTransfers= */ false,
+            /* renderFramesAutomatically= */ true,
+            taskExecutor,
+            MoreExecutors.directExecutor(),
+            listener,
+            /* textureOutputListener= */ null,
+            /* textureOutputCapacity= */ 1);
+    Constructor<DefaultVideoFrameProcessor> constructor =
+        DefaultVideoFrameProcessor.class.getDeclaredConstructor(
+            android.content.Context.class,
+            GlObjectsProvider.class,
+            EGLDisplay.class,
+            EGLContext.class,
+            InputSwitcher.class,
+            VideoFrameProcessingTaskExecutor.class,
+            VideoFrameProcessor.Listener.class,
+            java.util.concurrent.Executor.class,
+            FinalShaderProgramWrapper.class,
+            boolean.class,
+            boolean.class,
+            ColorInfo.class);
+    constructor.setAccessible(true);
+    return constructor.newInstance(
+        getApplicationContext(),
+        glObjectsProvider,
+        /* eglDisplay= */ null,
+        /* eglContext= */ null,
+        inputSwitcher,
+        taskExecutor,
+        listener,
+        MoreExecutors.directExecutor(),
+        finalShaderProgramWrapper,
+        /* renderFramesAutomatically= */ true,
+        /* enableColorTransfers= */ false,
+        outputColorInfo);
+  }
+
+  private static InputSwitcher newInputSwitcher(
+      VideoFrameProcessingTaskExecutor taskExecutor,
+      GlObjectsProvider glObjectsProvider,
+      GlShaderProgram downstreamShaderProgram,
+      TextureManager textureManager,
+      Object input)
+      throws Exception {
+    InputSwitcher inputSwitcher = allocateInstance(InputSwitcher.class);
+    SparseArray<Object> inputs = new SparseArray<>();
+    inputs.put(VideoFrameProcessor.INPUT_TYPE_BITMAP, input);
+    setField(inputSwitcher, "glObjectsProvider", glObjectsProvider);
+    setField(inputSwitcher, "videoFrameProcessingTaskExecutor", taskExecutor);
+    setField(inputSwitcher, "downstreamShaderProgram", downstreamShaderProgram);
+    setField(inputSwitcher, "inputs", inputs);
+    setField(inputSwitcher, "activeTextureManager", textureManager);
+    return inputSwitcher;
+  }
+
+  private static Object newInput(TextureManager textureManager) throws Exception {
+    Class<?> inputClass = Class.forName(InputSwitcher.class.getName() + "$Input");
+    Constructor<?> constructor = inputClass.getDeclaredConstructor(TextureManager.class);
+    constructor.setAccessible(true);
+    return constructor.newInstance(textureManager);
+  }
+
+  private static Object newInputStreamInfo(
+      int inputType, List<?> effects, FrameInfo frameInfo) throws Exception {
+    Class<?> inputStreamInfoClass =
+        Class.forName(DefaultVideoFrameProcessor.class.getName() + "$InputStreamInfo");
+    Constructor<?> constructor =
+        inputStreamInfoClass.getDeclaredConstructor(int.class, List.class, FrameInfo.class);
+    constructor.setAccessible(true);
+    return constructor.newInstance(inputType, effects, frameInfo);
+  }
+
+  private static void invokeConfigureEffects(
+      DefaultVideoFrameProcessor processor, Object inputStreamInfo) throws Exception {
+    Method method =
+        DefaultVideoFrameProcessor.class.getDeclaredMethod(
+            "configureEffects", inputStreamInfo.getClass(), boolean.class);
+    method.setAccessible(true);
+    invoke(method, processor, inputStreamInfo, /* forceReconfigure= */ false);
+  }
+
+  private static void invokeInputSetSamplingGlShaderProgram(
+      Object input, ExternalShaderProgram externalShaderProgram) throws Exception {
+    Method method =
+        input.getClass().getDeclaredMethod(
+            "setSamplingGlShaderProgram", ExternalShaderProgram.class);
+    method.setAccessible(true);
+    invoke(method, input, externalShaderProgram);
+  }
+
+  private static void setInputColorInfoIfPresent(Object input, ColorInfo colorInfo)
+      throws Exception {
+    try {
+      Field field = input.getClass().getDeclaredField("inputColorInfo");
+      field.setAccessible(true);
+      field.set(input, colorInfo);
+    } catch (NoSuchFieldException e) {
+      // The field does not exist before the fix.
+    }
+  }
+
+  private static VideoFrameProcessingTaskExecutor newTaskExecutor() {
+    return new VideoFrameProcessingTaskExecutor(
+        Util.newSingleThreadExecutor("DefaultVideoFrameProcessorColorChangeTest"),
+        /* shouldShutdownExecutorService= */ true,
+        exception -> {
+          throw new AssertionError(exception);
+        });
+  }
+
+  private static void release(VideoFrameProcessingTaskExecutor taskExecutor) throws Exception {
+    try {
+      taskExecutor.release(
+          () -> {
+            // No GL objects are created in this reflected setup.
+          });
+    } catch (InterruptedException e) {
+      Thread.currentThread().interrupt();
+      throw e;
+    }
+  }
+
+  private static void setField(Object target, String fieldName, Object value) throws Exception {
+    Field field = target.getClass().getDeclaredField(fieldName);
+    field.setAccessible(true);
+    field.set(target, value);
+  }
+
+  @SuppressWarnings("unchecked")
+  private static <T> T allocateInstance(Class<T> clazz) throws Exception {
+    return (T) new ObjenesisStd().newInstance(clazz);
+  }
+
+  private static void invoke(Method method, Object target, Object... arguments) throws Exception {
+    try {
+      method.invoke(target, arguments);
+    } catch (InvocationTargetException e) {
+      Throwable cause = e.getCause();
+      if (cause instanceof Exception) {
+        throw (Exception) cause;
+      }
+      if (cause instanceof Error) {
+        throw (Error) cause;
+      }
+      throw new RuntimeException(cause);
+    }
+  }
+}
